#include<bits/stdc++.h>
using namespace std;
const int N=500005;
int cnt,cnt2,dfn[N],low[N],n,m,vis[N];
stack<int> s;
vector<int> g[N],ans[N];
void tarjan(int u,int fa)
{
    dfn[u]=low[u]=++cnt;
    int cnt3=0;
    s.push(u);
    for(int i=0;i<g[u].size();i++)
    {
        int v=g[u][i];
		if(dfn[v]==0)
        {
            cnt3++;
			tarjan(v,u);
			low[u]=min(low[u],low[v]);
		}
        else if(dfn[v]<dfn[u]&&v!=fa) low[u]=min(low[u],dfn[v]);
    }
    if(low[u]==dfn[u])
    {
        cnt2++;
        while(1)
        {
            int now=s.top();
            s.pop();
            ans[cnt2].push_back(now);
            if(now==u) break;
        }
    }
}
int main()
{
    cin>>n>>m;
    for(int i=1;i<=m;i++)
    {
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
    {
        if(dfn[i]==0) tarjan(i,-1);
    }
    cout<<cnt2<<'\n';
    for(int i=1;i<=cnt2;i++)
    {
        cout<<ans[i].size()<<" ";
        for(int j=0;j<ans[i].size();j++)
        {
            cout<<ans[i][j]<<" ";
        }
        cout<<"\n";
    }
    return 0;
}
